BEGIN;

DELETE FROM route_waypoints WHERE route_code = 'SIS2';
DELETE FROM service_routes WHERE route_code = 'SIS2';

VALUES ('SIS2', 'SIS2', 'SIS2 service imported from route waypoint files.', TRUE)
ON CONFLICT (code) DO UPDATE
SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  is_active = TRUE;

VALUES ('SIS2', 'SIS2', 
'SIS2 - KRPUS/KRKAN/CNSHA/CNNGB/CNSHK/MYPKG/INNSA/INMUN/PKKHI/KRPUS'
, 'ROUND', 'SIS2 route imported from waypoint files.', TRUE);


COMMIT;
